############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "niceTables.pl", "contextCurrency.pl", "contextForm.pl", "parserPopUp.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $before = random(40, 60, 0.10); Context("Currency")->flags->set(trimTrailingZeros => 1); $after = Currency($before*1.2); $proposed_solution = (random(0,1)) ? $before : $before + non_zero_random(-10, 10, 0.5); $proposed_bill = Currency($proposed_solution); $left = Formula("x + 0.2x"); $right = Formula($after->value); Context("LimitedNumeric"); $lefteval = Real($left->eval(x => $proposed_solution)); $righteval = Real($right->eval(x => $proposed_solution)); $dropdown = DropDown( ["Yes, it is a solution.", "No, it is not a solution."], ($lefteval == $righteval) ? 0 : 1, showInStatic => 0 );
############################################################ # Body ############################################################
BEGIN_PGML If your restaurant bill is [`x`] and you add [`20\%`] tip, the total is [`x + 0.20x\text{.}`] If the total was [`[$after]\text{,}`] then we have an equation [`[$left]=[$right]\text{.}`] Was the bill before tip [`[$proposed_bill]\text{?}`]
>> [@DataTable( [ [PGML('[`[$left->TeX]`]'), PGML('[`=`]'), PGML('[`[$right->TeX]`]'), ], [PGML('[_]{$lefteval}{3}'), PGML('[`\wonder{=}`]'), PGML('[`[$righteval->TeX]`]'), ], ], align => 'rcl', valign => 'middle',);@]* <<
[_]{$dropdown}{5}
END_PGML
